@@ -374,6 +374,35 @@ fn stmtCallsSelfMethodWithClassArg(stmt: ast.Node, class_names: []const []const
             for (i.else_body) |s| if (stmtCallsSelfMethodWithClassArg(s, class_names)) break :blk true;
