+        .for_stmt => |f| blk: {
+            for (f.body) |s| if (stmtCallsSelfMethodWithClassArg(s, class_names)) break :blk true;
+            if (f.orelse_body) |ob| for (ob) |s| if (stmtCallsSelfMethodWithClassArg(s, class_names)) break :blk true;
