+            break :blk false;
+        },
+        .with_stmt => |w| blk: {
+            for (w.body) |s| if (stmtCallsSelfMethodWithClassArg(s, class_names)) break :blk true;
+            break :blk false;
+        },
+        .match_stmt => |m| blk: {
+            for (m.cases) |case| {
+                for (case.body) |s| if (stmtCallsSelfMethodWithClassArg(s, class_names)) break :blk true;
+            }
+            break :blk false;
+        },
